@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix ns1: <https://ada.astromat.org/metadata/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a cdi:StructuredDataSet,
                        ns1:dataCube ;
                    ns1:componentType [ a ns1:SEMEDSElementalMapsCube ] ;
                    ns1:dataComponentResource "cube_SEMEDS_001.hdf5" ] ;
            sh:resultMessage "A StructuredDataSet should have physical mappings (cdi:hasPhysicalMapping) linking variables to their physical representation." ;
            sh:resultPath cdi:hasPhysicalMapping ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A StructuredDataSet should have physical mappings (cdi:hasPhysicalMapping) linking variables to their physical representation." ;
                    sh:minCount 1 ;
                    sh:path cdi:hasPhysicalMapping ;
                    sh:severity sh:Warning ] ] .

